INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Chest' FROM exercises WHERE name IN ('Bench Press', 'Push-Ups', 'Incline Dumbbell Press', 'Chest Flys', 'Cable Crossover', 'Chest Dips');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Back' FROM exercises WHERE name IN ('Bent Over Row', 'Lat Pulldown', 'Deadlift', 'Pull-Ups', 'T-Bar Row', 'Face Pulls');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Biceps' FROM exercises WHERE name IN ('Pull-Ups', 'Bicep Curls', 'Hammer Curls', 'Preacher Curls');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Triceps' FROM exercises WHERE name IN ('Tricep Pushdown', 'Skull Crushers', 'Bench Press', 'Chest Dips');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Quads' FROM exercises WHERE name IN ('Back Squat', 'Leg Press', 'Leg Extensions', 'Lunges');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Hamstrings' FROM exercises WHERE name IN ('Back Squat', 'Romanian Deadlift', 'Leg Curls');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Calves' FROM exercises WHERE name IN ('Calf Raises');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Shoulders' FROM exercises WHERE name IN ('Overhead Press', 'Lateral Raises', 'Arnold Press', 'Front Raises', 'Face Pulls');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Core' FROM exercises WHERE name IN ('Planks', 'Leg Raises', 'Russian Twists', 'Crunches');
INSERT INTO exercise_muscle_groups (exercise_id, muscle_group) SELECT id, 'Full Body' FROM exercises WHERE name IN ('Deadlift', 'Burpees', 'Row Machine');
